media_type.script:
try {
    var params = JSON.parse(value),
        req = new HttpRequest(),
        response,
        type = 'INFO',
        critical = "false";

    if (!params.client_key || params.client_key === '{ALERT.SENDTO}') {
        throw 'client_key is missing. Enter your Signalgrid Client Key in the "Send to" field of the User Media.';
    }

    if (!params.channel || params.channel === '{$SIGNALGRID_CHANNEL}') {
        throw 'channel is missing. Define the {$SIGNALGRID_CHANNEL} macro.';
    }

    var s = parseInt(params.severity_num);

    if (params.event_value == 0) {
        type = 'SUCCESS';
    } else {
        if (s >= 5) {
            type = 'CRIT';
            critical = "true";
        } else if (s == 4) {
            type = 'CRIT';
        } else if (s >= 2) {
            type = 'WARN';
        } else {
            type = 'INFO';
        }
    }

    req.addHeader('Content-Type: application/x-www-form-urlencoded');

    var data = 'client_key=' + encodeURIComponent(params.client_key) +
               '&channel=' + encodeURIComponent(params.channel) +
               '&title=' + encodeURIComponent(params.title) +
               '&body=' + encodeURIComponent(params.body) +
               '&type=' + encodeURIComponent(type) +
               '&critical=' + encodeURIComponent(critical);

    Zabbix.log(4, '[Signalgrid Webhook] Sending form data to: ' + params.client_key);

    response = req.post('https://api.signalgrid.co/v1/push', data);

    if (req.getStatus() !== 200) {
        throw 'Response code: ' + req.getStatus() + ' - ' + response;
    }

    return 'OK';
}
catch (error) {
    Zabbix.log(3, '[Signalgrid Webhook] Notification failed: ' + error);
    throw 'Notification failed: ' + error;
}

